from seed import SeedApi, StackInformation, TraceResponse, WorkspaceRunDetails

client = SeedApi(
    token="YOUR_TOKEN",
)
client.admin.storetracedworkspace(
    submission_id="submissionId",
    workspace_run_details=WorkspaceRunDetails(
        stdout="stdout",
    ),
    trace_responses=[
        TraceResponse(
            submission_id="submissionId",
            line_number=1,
