    ],
)

from seed import SeedApi, StackInformation, TracedFile, TraceResponseV2

client = SeedApi(
    token="YOUR_TOKEN",
)
client.admin.storetracedworkspacev2(
    submission_id="submissionId",
    request=[
        TraceResponseV2(
            submission_id="submissionId",
            line_number=1,
            file=TracedFile(
                filename="filename",
                directory="directory",
            ),
            stack=StackInformation(
                num_stack_frames=1,
            ),
        )
    ],
)

from seed import (
    FileInfo,
    ProblemDescription,
    ProblemDescriptionBoard_Html,
    ProblemFiles,
    SeedApi,
    TestCase,
    TestCaseWithExpectedResult,
    VariableTypeAndName,
    VariableTypeZero,
    VariableValueZero,
)

client = SeedApi(
    token="YOUR_TOKEN",
)
client.problem.createproblem(
    problem_name="problemName",
    problem_description=ProblemDescription(
        boards=[ProblemDescriptionBoard_Html()],
    ),
    files={
        "key": ProblemFiles(
            solution_file=FileInfo(
                filename="filename",
                contents="contents",
            ),
            read_only_files=[
                FileInfo(
                    filename="filename",
                    contents="contents",
                )
            ],
        )
    },
    input_params=[
        VariableTypeAndName(
            variable_type=VariableTypeZero(
                type="integerType",
            ),
            name="name",
        )
    ],
    output_type=VariableTypeZero(
        type="integerType",
    ),
    testcases=[
        TestCaseWithExpectedResult(
            test_case=TestCase(
                id="id",
                params=[
                    VariableValueZero(
                        type="integerValue",
                    )
                ],
            ),
            expected_result=VariableValueZero(
                type="integerValue",
            ),
        )
    ],
    method_name="methodName",
)

